
import React,{useEffect,useState}from"react";
import{createRoot}from"react-dom/client";
import{createClient}from"@supabase/supabase-js";
import"./style.css";

const supabase=createClient("https://yiileradnxvlvkikyuwi.supabase.co","sb_publishable_bCyn05Ht69i9AmFvQhf2IQ_s_MnTsuD");
const blank={owners:[],buildings:[],units:[],tenants:[],tenant_units:[],payments:[],payment_entries:[],tenant_adjustments:[],utility_ean_codes:[],meter_readings:[],utility_tariffs:[]};
const eur=n=>new Intl.NumberFormat("nl-BE",{style:"currency",currency:"EUR"}).format(Number(n||0));
const money=t=>Number(t?.base_rent??t?.rent??0)+Number(t?.additional_costs??0);
const validMonth=p=>Number(p?.year)>=2000&&Number(p?.month)>=1&&Number(p?.month)<=12;
const monthLabel=p=>validMonth(p)?new Date(Number(p.year),Number(p.month)-1,1).toLocaleString("en-GB",{month:"short",year:"numeric"}):"Invalid month";
const monthLongLabel=p=>validMonth(p)?new Date(Number(p.year),Number(p.month)-1,1).toLocaleString("en-GB",{month:"long",year:"numeric"}):"Invalid month";
const tableForType=type=>({owner:"owners",building:"buildings",unit:"units",tenant:"tenants",payment:"payments",adjustment:"tenant_adjustments",utility:"utility_ean_codes"}[type]||`${type}s`);
const adjustmentsForPayment=(db,id)=>db.tenant_adjustments.filter(x=>String(x.payment_id)===String(id)&&x.status!=="rejected");
const adjustmentNetForPayment=(db,id)=>adjustmentsForPayment(db,id).reduce((s,x)=>s+(x.adjustment_type==="charge"?Number(x.amount||0):-Number(x.amount||0)),0);
const creditTotalForPayment=(db,id)=>adjustmentsForPayment(db,id).filter(x=>x.adjustment_type!=="charge").reduce((s,x)=>s+Number(x.amount||0),0);
const chargeTotalForPayment=(db,id)=>adjustmentsForPayment(db,id).filter(x=>x.adjustment_type==="charge").reduce((s,x)=>s+Number(x.amount||0),0);

function App(){
 const[session,setSession]=useState(null),[db,setDb]=useState(blank),[page,setPage]=useState("dashboard"),[modal,setModal]=useState(null),[q,setQ]=useState("");
 useEffect(()=>{supabase.auth.getSession().then(({data})=>{setSession(data.session);if(data.session)load()});const{data}=supabase.auth.onAuthStateChange((_e,s)=>{setSession(s);if(s)load()});return()=>data.subscription.unsubscribe()},[]);
 async function load(){const names=Object.keys(blank);const res=await Promise.all(names.map(t=>supabase.from(t).select("*").order("id")));let next={};names.forEach((n,i)=>next[n]=res[i].data||[]);setDb(next)}
 if(!session)return <Login/>;
 return <div className="app"><aside><div className="brand"><div className="logo">🏠</div><div><h2>Property Manager Pro</h2><small>{session.user.email}</small></div></div><input className="search" value={q} onChange={e=>setQ(e.target.value)} placeholder="Search..."/>{["dashboard","owners","buildings","units","tenants","payments","utilities"].map(p=><button key={p} onClick={()=>setPage(p)}>{p}</button>)}<button onClick={()=>supabase.auth.signOut()}>Logout</button><h4>Portfolio</h4><Portfolio db={db} q={q} setModal={setModal}/></aside><main><header><div><h1>{cap(page)}</h1><small>React Sprint 2.1</small></div><div className="actions">{["owner","building","unit","tenant","payment","utility"].map(t=><button key={t} className={t==="owner"?"primary":""} onClick={()=>setModal({type:t})}>+ {cap(t)}</button>)}</div></header><section className="content">{page==="dashboard"&&<Dashboard db={db} setModal={setModal}/>} {page==="owners"&&<Owners db={db} setModal={setModal}/>} {page==="buildings"&&<Buildings db={db} setModal={setModal}/>} {page==="units"&&<Units db={db} setModal={setModal}/>} {page==="tenants"&&<Tenants db={db} setModal={setModal}/>} {page==="payments"&&<Payments db={db} setModal={setModal} reload={load}/>} {page==="utilities"&&<Utilities db={db} setModal={setModal}/>}</section></main>{modal&&<Modal modal={modal} setModal={setModal} db={db} reload={load}/>}</div>
}
function cap(s){return s[0].toUpperCase()+s.slice(1)}
function Login(){const[e,setE]=useState(""),[p,setP]=useState(""),[err,setErr]=useState("");async function login(){setErr("");const{error}=await supabase.auth.signInWithPassword({email:e,password:p});if(error)setErr(error.message)}return <div className="login"><div className="login-card"><h1>🏠 Property Manager Pro</h1><p>React Sprint 2.1</p><label>Email<input value={e} onChange={x=>setE(x.target.value)}/></label><label>Password<input type="password" value={p} onChange={x=>setP(x.target.value)}/></label><button className="primary full" onClick={login}>Login</button>{err&&<div className="error">{err}</div>}</div></div>}
function Dashboard({db,setModal}){let out=db.payments.reduce((s,p)=>s+Math.max(0,Number(p.expected_amount||0)-Number(p.paid_amount||0)),0);return <><div className="grid"><Card l="Owners" v={db.owners.length}/><Card l="Buildings" v={db.buildings.length}/><Card l="Units" v={db.units.length}/><Card l="Outstanding" v={eur(out)}/></div><Panel title="Quick Actions"><div className="tiles"><Tile t="+ Tenant" s="multi unit" onClick={()=>setModal({type:"tenant"})}/><Tile t="+ Payment" s="rent record" onClick={()=>setModal({type:"payment"})}/><Tile t="+ Owner" s="new owner" onClick={()=>setModal({type:"owner"})}/></div></Panel></>}
function Owners(p){return <List title="Owners" add={()=>p.setModal({type:"owner"})}>{p.db.owners.map(o=><Row key={o.id} t={o.name||"Owner"} s={`${o.email||""} ${o.phone||""}`} onClick={()=>p.setModal({type:"owner",item:o})}/>)}</List>}
function Buildings(p){return <List title="Buildings" add={()=>p.setModal({type:"building"})}>{p.db.buildings.map(b=>{let o=p.db.owners.find(x=>x.id===b.owner_id),c=p.db.units.filter(u=>u.building_id===b.id).length;return <Row key={b.id} t={b.name||"Building"} s={`${o?.name||"No owner"} · ${c} units · ${b.address||""}`} onClick={()=>p.setModal({type:"buildingProfile",item:b,tab:"overview"})}/>})}</List>}
function Units(p){return <List title="Units" add={()=>p.setModal({type:"unit"})}>{p.db.units.map(u=>{let b=p.db.buildings.find(x=>x.id===u.building_id),ts=tenantsForUnit(p.db,u.id).map(t=>t.name).join(", ");return <Row key={u.id} t={`${b?.name||"Building"} · Unit ${u.unit_number||""}`} s={ts||"Vacant"} onClick={()=>p.setModal({type:"unitDetails",item:u})}/>})}</List>}

function Tenants(p){
 return <List title="Tenants" add={()=>p.setModal({type:"tenant"})}>
  {p.db.tenants.map(t=>{const us=unitsForTenant(p.db,t.id).map(u=>unitLabel(p.db,u)).join(", ");return <Row key={t.id} t={t.name||"Tenant"} s={`${eur(money(t))} · ${us||"No units"}`} onClick={()=>p.setModal({type:"tenantProfile",item:t,tab:"overview"})}/>})}
 </List>
}
function Payments({db,setModal,reload}){
 const rows=[...db.payments].filter(validMonth).sort((a,b)=>(b.year-a.year)||(b.month-a.month));
 const[statusFilter,setStatusFilter]=useState("all"),[monthFilter,setMonthFilter]=useState(""),[search,setSearch]=useState("");
 const now=new Date(),currentYear=now.getFullYear(),currentMonth=now.getMonth()+1;
 const[openMonths,setOpenMonths]=useState(()=>({[`${currentYear}-${String(currentMonth).padStart(2,"0")}`]:true}));
 const[openYears,setOpenYears]=useState(()=>({[currentYear]:true}));
 const paidTotal=id=>db.payment_entries.filter(x=>String(x.payment_id)===String(id)).reduce((s,x)=>s+Number(x.amount||0),0);
 const statusFor=p=>{const paid=paidTotal(p.id),adjustments=adjustmentNetForPayment(db,p.id),due=Number(p.expected_amount||0),balance=Math.max(0,due+adjustments-paid);return balance<=0?"paid":paid>0||adjustmentsForPayment(db,p.id).length>0?"partial":"unpaid"};
 const filtered=rows.filter(p=>{const t=db.tenants.find(x=>x.id===p.tenant_id),st=statusFor(p),mk=`${p.year}-${String(p.month).padStart(2,"0")}`;return(statusFilter==="all"||st===statusFilter)&&(!monthFilter||mk===monthFilter)&&(!search||String(t?.name||"").toLowerCase().includes(search.toLowerCase()))});
 const years=filtered.reduce((acc,p)=>{if(!acc[p.year])acc[p.year]={};const k=`${p.year}-${String(p.month).padStart(2,"0")}`;(acc[p.year][k]||(acc[p.year][k]=[])).push(p);return acc},{});
 const currentKey=`${currentYear}-${String(currentMonth).padStart(2,"0")}`;
 const toggleYear=year=>{if(Number(year)!==currentYear)setOpenYears(x=>({...x,[year]:!x[year]}))};
 const toggleMonth=key=>{if(key!==currentKey)setOpenMonths(x=>({...x,[key]:!x[key]}))};
 async function gen(){const d=new Date(),y=d.getFullYear(),m=d.getMonth()+1;let c=0,s=0,f=0,msg="";for(const t of db.tenants.filter(x=>x.active!==false)){if(db.payments.some(p=>p.tenant_id===t.id&&Number(p.year)===y&&Number(p.month)===m)){s++;continue}const r=await supabase.from("payments").insert({tenant_id:t.id,year:y,month:m,expected_amount:money(t),paid_amount:0,status:"pending"});if(r.error){f++;msg=r.error.message}else c++}alert(`Created: ${c}\nAlready existed: ${s}\nFailed: ${f}`+(msg?`\n${msg}`:""));await reload()}
 return <><div className="payments-toolbar"><div className="status-tabs">{["all","paid","partial","unpaid"].map(s=><button key={s} className={statusFilter===s?"active":""} onClick={()=>setStatusFilter(s)}>{cap(s)}</button>)}</div><input type="month" value={monthFilter} onChange={e=>setMonthFilter(e.target.value)}/><input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search tenant..."/><button onClick={gen}>Generate This Month</button><button className="primary" onClick={()=>setModal({type:"payment"})}>+ Monthly account</button></div><div className="payment-years">{Object.entries(years).sort((a,b)=>Number(b[0])-Number(a[0])).map(([year,months])=>{const yearOpen=Number(year)===currentYear||Boolean(openYears[year]);return <section className="payment-year-group" key={year}><button className={`payment-year-header ${Number(year)===currentYear?"current":""}`} onClick={()=>toggleYear(year)}><span>{year}</span><small>{Number(year)===currentYear?"Current year":yearOpen?"Hide months":"Show months"}</small></button>{yearOpen&&<div className="payment-year-months">{Object.entries(months).sort((a,b)=>b[0].localeCompare(a[0])).map(([key,items])=>{const due=items.reduce((s,p)=>s+Number(p.expected_amount||0),0),paid=items.reduce((s,p)=>s+paidTotal(p.id),0),adjustments=items.reduce((s,p)=>s+adjustmentNetForPayment(db,p.id),0),balance=Math.max(0,due+adjustments-paid),open=key===currentKey||Boolean(openMonths[key]);return <section className={`payment-month-group ${open?"open":"closed"}`} key={key}><button className="payment-month-header" onClick={()=>toggleMonth(key)}><div className="payment-month-title"><h3>{monthLongLabel(items[0])}</h3><small>{items.length} tenant account{items.length===1?"":"s"}{key===currentKey?" · Current month":""}</small></div><div className="payment-month-total-cards"><div className="month-total-card due"><small>Due</small><b>{eur(due)}</b></div><div className="month-total-card paid"><small>Paid</small><b>{eur(paid)}</b></div><div className={`month-total-card balance ${balance>0?"has-balance":""}`}><small>Balance</small><b>{eur(balance)}</b></div></div><span className="month-toggle-text">{key===currentKey?"Always open":open?"Close":"Open"}</span></button>{open&&<div className="payments-table"><div className="payments-head"><span>Tenant</span><span>Due</span><span>Paid</span><span>Balance</span><span>Status</span></div>{items.map(p=>{const t=db.tenants.find(x=>x.id===p.tenant_id),pa=paidTotal(p.id),cr=adjustmentNetForPayment(db,p.id),du=Number(p.expected_amount||0),ba=Math.max(0,du+cr-pa),st=statusFor(p);return <div key={p.id} className="payments-row"><button className="tenant-name-link" onClick={()=>setModal({type:"tenantProfile",item:t,tab:"payments"})}>{t?.name||"Tenant"}</button><button className="payment-cell" onClick={()=>setModal({type:"paymentAccount",item:p})}>{eur(du)}</button><button className="payment-cell" onClick={()=>setModal({type:"paymentAccount",item:p})}>{eur(pa)}</button><button className="payment-cell" onClick={()=>setModal({type:"paymentAccount",item:p})}>{eur(ba)}</button><button className="payment-cell" onClick={()=>setModal({type:"paymentAccount",item:p})}><span className={`status-badge ${st}`}>{st==="paid"?"Paid in full":st==="partial"?"Partially paid":"Unpaid"}</span></button></div>})}</div>}</section>})}</div>}</section>})}{!Object.keys(years).length&&<div className="empty panel">No payments match the selected filters.</div>}</div></>
}
function Utilities({db,setModal}){
 const[buildingId,setBuildingId]=useState("");
 const[scope,setScope]=useState("");
 const[unitId,setUnitId]=useState("");
 const units=buildingId?db.units.filter(u=>String(u.building_id)===String(buildingId)):[];
 const visibleUtilities=!buildingId||!scope?[]:db.utility_ean_codes.filter(x=>{
  if(String(x.building_id)!==String(buildingId))return false;
  if(scope==="building")return x.scope==="building"&&!x.unit_id;
  return x.scope==="unit"&&String(x.unit_id)===String(unitId);
 });
 function resetAfterBuilding(value){setBuildingId(value);setScope("");setUnitId("")}
 const selectedBuilding=db.buildings.find(b=>String(b.id)===String(buildingId));
 const selectedUnit=db.units.find(u=>String(u.id)===String(unitId));
 return <div className="utilities-workspace">
  <div className="utilities-selector panel"><div className="panel-head"><h3>Utilities</h3></div><div className="panel-body utilities-flow">
   <label>1. Select building<select value={buildingId} onChange={e=>resetAfterBuilding(e.target.value)}><option value="">Choose building</option>{db.buildings.map(b=><option key={b.id} value={b.id}>{b.name}</option>)}</select></label>
   {buildingId&&<div className="scope-choice"><span>2. Select location</span><div><button className={scope==="building"?"active":""} onClick={()=>{setScope("building");setUnitId("")}}>Communal</button><button className={scope==="unit"?"active":""} onClick={()=>setScope("unit")}>Specific unit</button></div></div>}
   {buildingId&&scope==="unit"&&<label>3. Select unit<select value={unitId} onChange={e=>setUnitId(e.target.value)}><option value="">Choose unit</option>{units.map(u=><option key={u.id} value={u.id}>Unit {u.unit_number||u.id}</option>)}</select></label>}
  </div></div>
  {buildingId&&scope&&(scope==="building"||unitId)&&<div className="selected-utilities"><div className="selected-utilities-head"><div><h3>{selectedBuilding?.name||"Building"}</h3><small>{scope==="building"?"Communal utilities":`Unit ${selectedUnit?.unit_number||""}`}</small></div><button className="primary" onClick={()=>setModal({type:"utility",item:{building_id:Number(buildingId),unit_id:scope==="unit"?Number(unitId):null,scope,utility_type:"electricity",custom_name:"",estimate_cost:false,connected_meter:false}})}>+ Add utility</button></div><div className="utility-card-grid">{visibleUtilities.map(x=><UtilityCard key={x.id} utility={x} db={db} onClick={()=>setModal({type:"utilityAccount",item:x})}/>)}{!visibleUtilities.length&&<div className="empty wide">No utilities configured here yet.</div>}</div></div>}
 </div>
}

function Portfolio({db,q,setModal}){let s=q.toLowerCase();return <div>{db.owners.filter(o=>!s||String(o.name||"").toLowerCase().includes(s)).map(o=><div key={o.id}><div className="tree" onClick={()=>setModal({type:"owner",item:o})}>👤 {o.name||"Owner"}</div><div className="child">{db.buildings.filter(b=>b.owner_id===o.id).map(b=><div key={b.id}><div className="tree" onClick={()=>setModal({type:"buildingProfile",item:b,tab:"overview"})}>🏢 {b.name||"Building"}</div><div className="child">{db.units.filter(u=>u.building_id===b.id).map(u=><div key={u.id} className="tree" onClick={()=>setModal({type:"unitDetails",item:u})}>🚪 {u.unit_number||"Unit"}</div>)}</div></div>)}</div></div>)}</div>}
function Modal({modal,setModal,db,reload}){
 const now=new Date();
 const initialItem=modal.item||(modal.type==="payment"?{year:now.getFullYear(),month:now.getMonth()+1,paid_amount:0}:{});
 const[item,setItem]=useState(initialItem),[unitIds,setUnitIds]=useState(()=>modal.type==="tenant"?unitsForTenant(db,modal.item?.id).map(u=>u.id):[]);function set(k,v){setItem(x=>({...x,[k]:v}))}function toggle(id){setUnitIds(a=>a.includes(id)?a.filter(x=>x!==id):[...a,id])}
 if(modal.type==="buildingProfile")return <BuildingProfileModal building={modal.item} db={db} setModal={setModal} reload={reload} initialTab={modal.tab||"overview"}/>;
 if(modal.type==="tenantProfile")return <TenantProfileModal tenant={modal.item} db={db} setModal={setModal} reload={reload} initialTab={modal.tab||"overview"} parent={modal.parent||null}/>;
 if(modal.type==="paymentAccount")return <PaymentAccountModal payment={modal.item} db={db} setModal={setModal} reload={reload} parent={modal.parent||null}/>;
 if(modal.type==="unitDetails")return <UnitDetailsModal unit={modal.item} db={db} setModal={setModal} reload={reload} initialTab={modal.tab||"general"} parent={modal.parent||null}/>;
 if(modal.type==="utilityAccount")return <UtilityAccountModal utility={modal.item} db={db} setModal={setModal} reload={reload} parent={modal.parent||null}/>;
 async function save(){
  let table=tableForType(modal.type),payload=payloadFor(modal.type,item);
  if(modal.type==="utility"){if(!payload.building_id)return alert("Choose a building.");if(payload.scope==="unit"&&!payload.unit_id)return alert("Choose a unit.");if(!payload.utility_type&&!payload.custom_name)return alert("Choose or name a utility.");}
  if(modal.type==="adjustment"){
   if(!payload.tenant_id)return alert("Choose a tenant.");
   if(!payload.payment_id)return alert("Choose the month to apply this adjustment to.");
   if(payload.amount<=0)return alert("Adjustment amount must be greater than zero.");
  }
  if(modal.type==="payment"){
   if(!payload.tenant_id)return alert("Choose a tenant.");
   if(payload.year<2000||payload.month<1||payload.month>12)return alert("Choose a valid month.");
   if(payload.expected_amount<0)return alert("Rent due cannot be negative.");
   if(!modal.item?.id&&db.payments.some(p=>String(p.tenant_id)===String(payload.tenant_id)&&Number(p.year)===payload.year&&Number(p.month)===payload.month))return alert("A monthly account already exists for this tenant and month.");
  }
  let res=modal.item?.id?await supabase.from(table).update(payload).eq("id",modal.item.id):await supabase.from(table).insert(payload).select().single();
  if(res.error)return alert(res.error.message);
  let id=modal.item?.id||res.data?.id;
  if(modal.type==="tenant"){await supabase.from("tenant_units").delete().eq("tenant_id",id);if(unitIds.length){let r=await supabase.from("tenant_units").insert(unitIds.map(unit_id=>({tenant_id:id,unit_id})));if(r.error)return alert(r.error.message)}}
  await reload();setModal(modal.parent||null)
 }
 async function del(){if(!confirm("Delete?"))return;if(modal.type==="tenant")await supabase.from("tenant_units").delete().eq("tenant_id",modal.item.id);let r=await supabase.from(tableForType(modal.type)).delete().eq("id",modal.item.id);if(r.error)return alert(r.error.message);await reload();setModal(modal.parent||null)}
 return <div className="modal-bg"><div className="modal"><div className="modal-head"><h3>{modal.item?"Edit":"Add"} {modal.type}</h3><button onClick={()=>setModal(null)}>×</button></div><div className="modal-body"><Form type={modal.type} item={item} set={set} db={db} unitIds={unitIds} toggle={toggle} modal={modal}/></div><div className="modal-foot">{modal.item?.id&&<button className="danger" onClick={del}>Delete</button>}<span/>{modal.parent&&<button onClick={()=>setModal(modal.parent)}>Back</button>}<button onClick={()=>setModal(null)}>{modal.parent?"Close":"Cancel"}</button><button className="primary" onClick={save}>Save</button></div></div></div>
}

function BuildingProfileModal({building,db,setModal,reload,initialTab}){
 const[tab,setTab]=useState(initialTab);
 const owner=db.owners.find(x=>String(x.id)===String(building.owner_id));
 const units=db.units.filter(u=>String(u.building_id)===String(building.id));
 const unitIds=units.map(u=>u.id);
 const tenants=db.tenants.filter(t=>unitsForTenant(db,t.id).some(u=>unitIds.some(id=>String(id)===String(u.id))));
 const tenantIds=tenants.map(t=>t.id);
 const payments=[...db.payments].filter(p=>tenantIds.some(id=>String(id)===String(p.tenant_id))&&validMonth(p)).sort((a,b)=>(b.year-a.year)||(b.month-a.month));
 const paidTotal=id=>db.payment_entries.filter(x=>String(x.payment_id)===String(id)).reduce((s,x)=>s+Number(x.amount||0),0);
 const monthlyRent=tenants.reduce((s,t)=>s+money(t),0);
 const outstanding=payments.reduce((s,p)=>s+Math.max(0,Number(p.expected_amount||0)+adjustmentNetForPayment(db,p.id)-paidTotal(p.id)),0);
 const occupied=units.filter(u=>tenantsForUnit(db,u.id).length>0).length;
 const vacant=Math.max(0,units.length-occupied);
 const utilities=db.utility_ean_codes.filter(x=>String(x.building_id)===String(building.id)||unitIds.some(id=>String(id)===String(x.unit_id)));
 const communal=utilities.filter(x=>x.scope==="building"||!x.unit_id);
 const unitUtilities=utilities.filter(x=>x.scope==="unit"&&x.unit_id);

 return <div className="modal-bg"><div className="modal building-profile-modal">
  <div className="modal-head"><div><h3>{building.name||"Building"}</h3><small>{building.address||"No address"}</small></div><button onClick={()=>setModal(null)}>×</button></div>
  <div className="building-profile-summary">
   <div><small>Total units</small><b>{units.length}</b></div>
   <div><small>Occupied</small><b>{occupied}</b></div>
   <div><small>Vacant</small><b>{vacant}</b></div>
   <div><small>Monthly rent</small><b>{eur(monthlyRent)}</b></div>
   <div><small>Outstanding</small><b>{eur(outstanding)}</b></div>
   <div><small>Owner</small><b>{owner?.name||"No owner"}</b></div>
  </div>
  <div className="building-profile-tabs">{["overview","units","tenants","payments","utilities","maintenance","reports"].map(x=><button key={x} className={tab===x?"active":""} onClick={()=>setTab(x)}>{cap(x)}</button>)}</div>
  <div className="building-profile-body">
   {tab==="overview"&&<div className="building-overview-grid">
    <div><small>Building name</small><b>{building.name||"—"}</b></div><div><small>Owner</small><b>{owner?.name||"—"}</b></div>
    <div className="wide"><small>Address</small><b>{building.address||"—"}</b></div>
    <div><small>Occupancy</small><b>{units.length?`${Math.round(occupied/units.length*100)}%`:"0%"}</b></div><div><small>Tenants</small><b>{tenants.length}</b></div>
    <div className="wide profile-actions"><button onClick={()=>setModal({type:"building",item:building,parent:{type:"buildingProfile",item:building,tab:"overview"}})}>Edit building information</button></div>
   </div>}
   {tab==="units"&&<div className="building-unit-grid">{units.map(u=>{const ts=tenantsForUnit(db,u.id);return <button key={u.id} onClick={()=>setModal({type:"unitDetails",item:u,parent:{type:"buildingProfile",item:building,tab:"units"}})}><b>Unit {u.unit_number||u.id}</b><small>{u.floor?`Floor ${u.floor} · `:""}{ts.map(t=>t.name).join(", ")||"Vacant"}</small></button>})}{!units.length&&<div className="empty">No units in this building.</div>}</div>}
   {tab==="tenants"&&<div className="building-tenant-list">{tenants.map(t=><button key={t.id} onClick={()=>setModal({type:"tenantProfile",item:t,tab:"overview",parent:{type:"buildingProfile",item:building,tab:"tenants"}})}><span><b>{t.name||"Tenant"}</b><small>{unitsForTenant(db,t.id).filter(u=>unitIds.some(id=>String(id)===String(u.id))).map(u=>`Unit ${u.unit_number||u.id}`).join(", ")}</small></span><strong>{eur(money(t))}</strong></button>)}{!tenants.length&&<div className="empty">No tenants in this building.</div>}</div>}
   {tab==="payments"&&<BuildingPaymentsAccordion building={building} payments={payments} db={db} setModal={setModal}/>}
   {tab==="utilities"&&<><div className="building-section-title"><h4>Communal utilities</h4><button className="primary" onClick={()=>setModal({type:"utility",item:{building_id:building.id,unit_id:null,scope:"building",utility_type:"electricity"}})}>+ Communal utility</button></div><div className="utility-card-grid">{communal.map(x=><UtilityCard key={x.id} utility={x} db={db} onClick={()=>setModal({type:"utilityAccount",item:x,parent:{type:"buildingProfile",item:building,tab:"utilities"}})}/>)}{!communal.length&&<div className="empty wide">No communal utilities.</div>}</div><div className="building-section-title second"><h4>Unit utilities</h4></div><div className="utility-card-grid">{unitUtilities.map(x=><UtilityCard key={x.id} utility={x} db={db} onClick={()=>setModal({type:"utilityAccount",item:x,parent:{type:"buildingProfile",item:building,tab:"utilities"}})}/>)}{!unitUtilities.length&&<div className="empty wide">No unit utilities.</div>}</div></>}
   {tab==="maintenance"&&<div className="profile-placeholder"><h4>Building maintenance</h4><p>Open jobs, contractors, costs, photos and invoices will be linked here in the Maintenance sprint.</p></div>}
   {tab==="reports"&&<div className="profile-placeholder"><h4>Building reports</h4><p>PDF and Excel exports for units, tenants, payments and utilities will be added here.</p></div>}
  </div>
  <div className="modal-foot"><button onClick={()=>setModal(null)}>Close</button></div>
 </div></div>
}

function BuildingPaymentsAccordion({building,payments,db,setModal}){
 const now=new Date(),currentYear=now.getFullYear(),currentMonth=now.getMonth()+1,currentKey=`${currentYear}-${String(currentMonth).padStart(2,"0")}`;
 const[openYears,setOpenYears]=useState(()=>({[currentYear]:true}));
 const[openMonths,setOpenMonths]=useState(()=>({[currentKey]:true}));
 const paidTotal=id=>db.payment_entries.filter(x=>String(x.payment_id)===String(id)).reduce((s,x)=>s+Number(x.amount||0),0);
 const years=payments.reduce((acc,p)=>{if(!acc[p.year])acc[p.year]={};const key=`${p.year}-${String(p.month).padStart(2,"0")}`;(acc[p.year][key]||(acc[p.year][key]=[])).push(p);return acc},{});
 return <div className="building-payment-accordion">{Object.entries(years).sort((a,b)=>Number(b[0])-Number(a[0])).map(([year,months])=>{const yearOpen=Number(year)===currentYear||openYears[year];return <section className="building-payment-year" key={year}><button className="building-payment-year-head" onClick={()=>Number(year)!==currentYear&&setOpenYears(x=>({...x,[year]:!x[year]}))}><b>{year}</b><span>{Number(year)===currentYear?"Current year":yearOpen?"Close":"Open"}</span></button>{yearOpen&&<div className="building-payment-months">{Object.entries(months).sort((a,b)=>b[0].localeCompare(a[0])).map(([key,items])=>{const open=key===currentKey||openMonths[key],due=items.reduce((s,p)=>s+Number(p.expected_amount||0),0),paid=items.reduce((s,p)=>s+paidTotal(p.id),0),adjustments=items.reduce((s,p)=>s+adjustmentNetForPayment(db,p.id),0),balance=Math.max(0,due+adjustments-paid);return <section className="building-payment-month" key={key}><button className="building-payment-month-head" onClick={()=>key!==currentKey&&setOpenMonths(x=>({...x,[key]:!x[key]}))}><div><b>{monthLongLabel(items[0])}</b><small>{items.length} accounts{key===currentKey?" · Current month":""}</small></div><div className="building-month-totals"><span>Due <b>{eur(due)}</b></span><span>Paid <b>{eur(paid)}</b></span><span>Balance <b>{eur(balance)}</b></span></div><em>{key===currentKey?"Always open":open?"Close":"Open"}</em></button>{open&&<div className="building-payment-list">{items.map(p=>{const t=db.tenants.find(x=>x.id===p.tenant_id),pa=paidTotal(p.id),cr=adjustmentNetForPayment(db,p.id),du=Number(p.expected_amount||0),ba=Math.max(0,du+cr-pa),status=ba<=0?"paid":pa>0||adjustmentsForPayment(db,p.id).length>0?"partial":"unpaid";return <button key={p.id} onClick={()=>setModal({type:"paymentAccount",item:p,parent:{type:"buildingProfile",item:building,tab:"payments"}})}><span><b>{t?.name||"Tenant"}</b></span><span>{eur(du)}</span><span>{eur(pa)}</span><span>{eur(ba)}</span><span className={`status-badge ${status}`}>{status==="paid"?"Paid":status==="partial"?"Partial":"Unpaid"}</span></button>})}</div>}</section>})}</div>}</section>})}{!payments.length&&<div className="empty">No payments for this building.</div>}</div>
}

function TenantProfileModal({tenant,db,setModal,reload,initialTab,parent}){
 const[tab,setTab]=useState(initialTab);
 const units=unitsForTenant(db,tenant.id),unitIds=units.map(u=>u.id);
 const payments=[...db.payments].filter(p=>String(p.tenant_id)===String(tenant.id)&&validMonth(p)).sort((a,b)=>(b.year-a.year)||(b.month-a.month));
 const utilities=db.utility_ean_codes.filter(u=>u.scope==="unit"&&unitIds.some(id=>String(id)===String(u.unit_id)));
 const paidTotal=id=>db.payment_entries.filter(x=>String(x.payment_id)===String(id)).reduce((s,x)=>s+Number(x.amount||0),0);
 const adjustments=db.tenant_adjustments.filter(c=>String(c.tenant_id)===String(tenant.id)&&c.status!=="rejected");
 const totalAdjustments=adjustments.reduce((s,c)=>s+(c.adjustment_type==="charge"?Number(c.amount||0):-Number(c.amount||0)),0);
 const outstanding=payments.reduce((s,p)=>s+Math.max(0,Number(p.expected_amount||0)+adjustmentNetForPayment(db,p.id)-paidTotal(p.id)),0);
 return <div className="modal-bg"><div className="modal tenant-profile-modal"><div className="modal-head"><div><h3>{tenant.name||"Tenant"}</h3><small>{units.map(u=>unitLabel(db,u)).join(", ")||"No units assigned"}</small></div><button onClick={()=>setModal(null)}>×</button></div><div className="tenant-profile-summary"><div><small>Monthly rent</small><b>{eur(money(tenant))}</b></div><div><small>Outstanding</small><b>{eur(outstanding)}</b></div><div><small>Units</small><b>{units.length}</b></div><div><small>Adjustments</small><b>{eur(totalAdjustments)}</b></div></div><div className="tenant-profile-tabs">{["overview","payments","adjustments","units","utilities","maintenance"].map(x=><button key={x} className={tab===x?"active":""} onClick={()=>setTab(x)}>{cap(x)}</button>)}</div><div className="tenant-profile-body">
 {tab==="overview"&&<div className="tenant-overview-grid"><div><small>Name</small><b>{tenant.name||"—"}</b></div><div><small>Phone</small><b>{tenant.phone||"—"}</b></div><div><small>Email</small><b>{tenant.email||"—"}</b></div><div><small>IBAN</small><b>{tenant.iban||"—"}</b></div><div><small>Base rent</small><b>{eur(tenant.base_rent??tenant.rent??0)}</b></div><div><small>Costs</small><b>{eur(tenant.additional_costs||0)}</b></div><div className="wide"><small>Current units</small><b>{units.map(u=>unitLabel(db,u)).join(", ")||"No units assigned"}</b></div><div className="wide profile-actions"><button onClick={()=>setModal({type:"tenant",item:tenant,parent:{type:"tenantProfile",item:tenant,tab:"overview",parent}})}>Edit tenant information</button></div></div>}
 {tab==="payments"&&<div className="tenant-payment-list">{payments.map(p=>{const paid=paidTotal(p.id),adjustment=adjustmentNetForPayment(db,p.id),due=Number(p.expected_amount||0),balance=Math.max(0,due+adjustment-paid),status=balance<=0?"paid":paid>0||adjustmentsForPayment(db,p.id).length>0?"partial":"unpaid";return <button className="tenant-payment-row" key={p.id} onClick={()=>setModal({type:"paymentAccount",item:p,parent:{type:"tenantProfile",item:tenant,tab:"payments"}})}><span><b>{monthLongLabel(p)}</b></span><span>Due {eur(due)}</span><span>Paid {eur(paid)}</span><span>Balance {eur(balance)}</span><span className={`status-badge ${status}`}>{status==="paid"?"Paid":status==="partial"?"Partial":"Unpaid"}</span></button>})}{!payments.length&&<div className="empty">No payment history.</div>}</div>}
 {tab==="adjustments"&&<div className="tenant-adjustment-section">
  <div className="tenant-adjustment-toolbar">
   <h4>Tenant adjustments</h4>
   <button className="primary" onClick={()=>setModal({type:"adjustment",item:{tenant_id:tenant.id,adjustment_type:"credit",adjustment_date:new Date().toISOString().slice(0,10),status:"approved"},parent:{type:"tenantProfile",item:tenant,tab:"adjustments",parent}})}>+ Add adjustment</button>
  </div>
  <div className="tenant-adjustment-list">
   {adjustments.map(c=>{const p=db.payments.find(x=>String(x.id)===String(c.payment_id));async function deleteAdjustment(){if(!confirm(`Delete this adjustment of ${eur(c.amount)}?`))return;const{error}=await supabase.from("tenant_adjustments").delete().eq("id",c.id);if(error)return alert(error.message);await reload();setModal({type:"tenantProfile",item:tenant,tab:"adjustments",parent})}return <div className="tenant-adjustment-row" key={c.id}>
    <button className="tenant-adjustment-main" onClick={()=>setModal({type:"adjustment",item:c,parent:{type:"tenantProfile",item:tenant,tab:"adjustments",parent}})}><span><b>{c.reason||cap(c.adjustment_type||"credit")}</b><small>{cap(c.adjustment_type||"credit")} · {c.adjustment_date||""} · {p?monthLongLabel(p):"Unassigned"}</small></span></button>
    <strong className={c.adjustment_type==="charge"?"charge":"credit"}>{c.adjustment_type==="charge"?"+":"-"}{eur(c.amount)}</strong>
    <span className={`adjustment-status ${c.status||"approved"}`}>{cap(c.status||"approved")}</span>
    <div className="tenant-adjustment-actions"><button onClick={()=>setModal({type:"adjustment",item:c,parent:{type:"tenantProfile",item:tenant,tab:"adjustments",parent}})}>Edit</button><button className="danger" onClick={deleteAdjustment}>Delete</button></div>
   </div>})}
   {!adjustments.length&&<div className="empty">No adjustments yet.</div>}
  </div>
 </div>}
 {tab==="units"&&<div className="tenant-units-grid">{units.map(u=>{const b=db.buildings.find(x=>x.id===u.building_id);return <button key={u.id} onClick={()=>setModal({type:"unitDetails",item:u})}><b>{b?.name||"Building"} · Unit {u.unit_number||""}</b><small>Floor {u.floor||"—"}</small></button>})}{!units.length&&<div className="empty">No units assigned.</div>}</div>}
 {tab==="utilities"&&<div className="utility-card-grid">{utilities.map(x=><UtilityCard key={x.id} utility={x} db={db} onClick={()=>setModal({type:"utilityAccount",item:x})}/>)}{!utilities.length&&<div className="empty wide">No unit utilities connected to this tenant.</div>}</div>}
 {tab==="maintenance"&&<div className="profile-placeholder"><h4>Maintenance</h4><p>Tenant and unit maintenance records will be linked here in the next sprint.</p></div>}
 </div><div className="modal-foot"><span/>{parent&&<button onClick={()=>setModal(parent)}>Back</button>}<button onClick={()=>setModal(null)}>Close</button></div></div></div>
}
function PaymentAccountModal({payment,db,setModal,reload,parent}){
 const tenant=db.tenants.find(x=>x.id===payment.tenant_id);
 const entries=db.payment_entries.filter(x=>String(x.payment_id)===String(payment.id)).sort((a,b)=>String(b.payment_date||"").localeCompare(String(a.payment_date||"")));
 const paid=entries.reduce((s,x)=>s+Number(x.amount||0),0),adjustments=adjustmentsForPayment(db,payment.id),charges=chargeTotalForPayment(db,payment.id),credits=creditTotalForPayment(db,payment.id),adjustmentNet=charges-credits,due=Number(payment.expected_amount||0),balance=Math.max(0,due+adjustmentNet-paid),status=balance<=0?"paid":paid>0||adjustments.length>0?"partial":"unpaid";
 const[showAdd,setShowAdd]=useState(false),[amount,setAmount]=useState(""),[date,setDate]=useState(new Date().toISOString().slice(0,10)),[method,setMethod]=useState("bank"),[reference,setReference]=useState(""),[notes,setNotes]=useState("");
 async function sync(){const[{data:paymentRows},{data:adjustmentRows}]=await Promise.all([supabase.from("payment_entries").select("amount").eq("payment_id",payment.id),supabase.from("tenant_adjustments").select("amount,adjustment_type,status").eq("payment_id",payment.id)]);const total=(paymentRows||[]).reduce((s,x)=>s+Number(x.amount||0),0),net=(adjustmentRows||[]).filter(x=>x.status!=="rejected").reduce((s,x)=>s+(x.adjustment_type==="charge"?Number(x.amount||0):-Number(x.amount||0)),0),remaining=Math.max(0,due+net-total),st=remaining<=0?"paid":total>0||(adjustmentRows||[]).some(x=>x.status!=="rejected")?"partial":"pending";await supabase.from("payments").update({paid_amount:total,status:st}).eq("id",payment.id)}
 async function add(){let v=Number(amount||0);if(v<=0)return alert("Enter a payment amount.");let r=await supabase.from("payment_entries").insert({payment_id:payment.id,amount:v,payment_date:date,method,reference,notes});if(r.error)return alert(r.error.message);await sync();await reload();setModal({type:"paymentAccount",item:payment,parent});}
 async function remove(id){if(!confirm("Delete this payment entry?"))return;let r=await supabase.from("payment_entries").delete().eq("id",id);if(r.error)return alert(r.error.message);await sync();await reload();setModal({type:"paymentAccount",item:payment,parent});}
 async function deleteAccount(){if(!confirm("Delete this monthly account and all payment entries?"))return;let r=await supabase.from("payments").delete().eq("id",payment.id);if(r.error)return alert(r.error.message);await reload();setModal(parent||null)}
 return <div className="modal-bg"><div className="modal payment-account-modal compact-payment-modal">
  <div className="modal-head"><div><h3>{tenant?.name||"Tenant"} · {monthLongLabel(payment)}</h3><small>Monthly rent account</small></div><button onClick={()=>setModal(null)}>×</button></div>
  <div className="payment-summary payment-summary-five"><div><small>Rent due</small><b>{eur(due)}</b></div><div><small>Adjustments</small><b>{adjustmentNet>=0?"+":"-"}{eur(Math.abs(adjustmentNet))}</b></div><div><small>Paid so far</small><b>{eur(paid)}</b></div><div><small>Still due</small><b>{eur(balance)}</b></div><div><small>Status</small><span className={`status-badge ${status}`}>{status==="paid"?"Paid in full":status==="partial"?"Partially paid":"Unpaid"}</span></div></div>
  <div className="compact-payment-body">
   <div className="payment-history"><h4>Payment history</h4>{entries.length?entries.map(e=><div className="payment-entry" key={e.id}><div><b>{eur(e.amount)}</b><small>{e.payment_date||""} · {cap(e.method||"other")}{e.reference?` · ${e.reference}`:""}</small>{e.notes&&<small>{e.notes}</small>}</div><button className="danger subtle" onClick={()=>remove(e.id)}>Delete</button></div>):<div className="empty">No payments added yet.</div>}</div>
   <div className="adjustment-history"><div className="adjustment-history-head"><h4>Adjustments</h4><button onClick={()=>setModal({type:"adjustment",item:{tenant_id:tenant?.id,payment_id:payment.id,adjustment_type:"credit",adjustment_date:new Date().toISOString().slice(0,10),status:"approved"},parent:{type:"paymentAccount",item:payment,parent}})}>+ Add adjustment</button></div>{adjustments.length?adjustments.map(c=><div className="adjustment-entry" key={c.id}><div><b className={c.adjustment_type==="charge"?"adjustment-charge":"adjustment-credit"}>{c.adjustment_type==="charge"?"+":"-"}{eur(c.amount)}</b><small>{cap(c.adjustment_type||"credit")} · {c.adjustment_date||""} · {c.reason||"Adjustment"} · {cap(c.status||"approved")}</small>{c.notes&&<small>{c.notes}</small>}</div><button className="danger subtle" onClick={async()=>{if(!confirm("Delete this adjustment?"))return;const{error}=await supabase.from("tenant_adjustments").delete().eq("id",c.id);if(error)return alert(error.message);await reload();setModal({type:"paymentAccount",item:payment,parent})}}>Delete</button></div>):<div className="empty">No adjustments for this month.</div>}</div>
   <div className="compact-add-payment">
    <button className="primary" onClick={()=>setShowAdd(x=>!x)}>{showAdd?"Hide payment form":"+ Add payment"}</button>
    {showAdd&&<div className="add-payment-collapsible"><div className="compact-form-grid"><Field l="Amount" type="number" v={amount} set={setAmount}/><label>Date<input type="date" value={date} onChange={e=>setDate(e.target.value)}/></label><label>Method<select value={method} onChange={e=>setMethod(e.target.value)}><option value="bank">Bank</option><option value="cash">Cash</option><option value="wise">Wise</option><option value="other">Other</option></select></label><Field l="Reference" v={reference} set={setReference}/><label className="wide">Notes<textarea value={notes} onChange={e=>setNotes(e.target.value)}/></label></div><button className="primary" onClick={add}>Save payment</button></div>}
   </div>
  </div>
  <div className="modal-foot"><button className="danger" onClick={deleteAccount}>Delete monthly account</button><span/>{parent&&<button onClick={()=>setModal(parent)}>Back</button>}<button onClick={()=>setModal(null)}>Close</button></div>
 </div></div>
}
function Form({type,item,set,db,unitIds,toggle,modal}){if(type==="owner")return <><Field l="Name" v={item.name} set={v=>set("name",v)}/><Field l="Email" v={item.email} set={v=>set("email",v)}/><Field l="Phone" v={item.phone} set={v=>set("phone",v)}/><Field l="IBAN" v={item.iban} set={v=>set("iban",v)}/><label className="wide">Notes<textarea value={item.notes||""} onChange={e=>set("notes",e.target.value)}/></label></>;if(type==="building")return <><label>Owner<select value={item.owner_id||""} onChange={e=>set("owner_id",e.target.value?Number(e.target.value):null)}><option value="">No owner</option>{db.owners.map(o=><option key={o.id} value={o.id}>{o.name}</option>)}</select></label><Field l="Name" v={item.name} set={v=>set("name",v)}/><label className="wide">Address<input value={item.address||""} onChange={e=>set("address",e.target.value)}/></label></>;if(type==="unit")return <><label>Building<select value={item.building_id||""} onChange={e=>set("building_id",e.target.value?Number(e.target.value):null)}><option value="">Choose building</option>{db.buildings.map(b=><option key={b.id} value={b.id}>{b.name}</option>)}</select></label><Field l="Unit number" v={item.unit_number} set={v=>set("unit_number",v)}/><Field l="Floor" v={item.floor} set={v=>set("floor",v)}/></>;if(type==="tenant")return <><div className="wide"><TenantUnitsPicker db={db} unitIds={unitIds} toggle={toggle}/></div><Field l="Name" v={item.name} set={v=>set("name",v)}/><Field l="Base rent" type="number" v={item.base_rent??item.rent??0} set={v=>set("base_rent",v)}/><Field l="Costs" type="number" v={item.additional_costs??0} set={v=>set("additional_costs",v)}/><Field l="Phone" v={item.phone} set={v=>set("phone",v)}/><Field l="Email" v={item.email} set={v=>set("email",v)}/><Field l="IBAN" v={item.iban} set={v=>set("iban",v)}/></>;if(type==="payment"){
 const ym=validMonth(item)?`${item.year}-${String(item.month).padStart(2,"0")}`:"";
 return <><label>Tenant<select value={item.tenant_id||""} onChange={e=>{let id=Number(e.target.value),t=db.tenants.find(x=>x.id===id);set("tenant_id",id);if(t&&!item.expected_amount)set("expected_amount",money(t))}}><option value="">Choose tenant</option>{db.tenants.map(t=><option key={t.id} value={t.id}>{t.name}</option>)}</select></label><label>Month<input type="month" value={ym} onChange={e=>{const value=e.target.value;if(!value){set("year",0);set("month",0);return}set("year",Number(value.slice(0,4)));set("month",Number(value.slice(5,7)))}}/></label><Field l="Rent due" type="number" v={item.expected_amount??0} set={v=>set("expected_amount",v)}/><div className="wide form-note">Create the monthly account first. Open it from the Payments list to add one or more installments.</div></>}
 if(type==="adjustment"){
  const tenantPayments=db.payments.filter(p=>String(p.tenant_id)===String(item.tenant_id)&&validMonth(p)).sort((a,b)=>(b.year-a.year)||(b.month-a.month));
  return <><label>Tenant<select value={item.tenant_id||""} onChange={e=>{set("tenant_id",Number(e.target.value)||null);set("payment_id",null)}}><option value="">Choose tenant</option>{db.tenants.map(t=><option key={t.id} value={t.id}>{t.name}</option>)}</select></label><label>Apply to month<select value={item.payment_id||""} onChange={e=>set("payment_id",Number(e.target.value)||null)} disabled={!item.tenant_id}><option value="">{item.tenant_id?"Choose month":"Choose tenant first"}</option>{tenantPayments.map(p=><option key={p.id} value={p.id}>{monthLongLabel(p)} · Due {eur(p.expected_amount)}</option>)}</select></label><label>Type<select value={item.adjustment_type||"credit"} onChange={e=>set("adjustment_type",e.target.value)}><option value="credit">Credit</option><option value="charge">Charge</option></select></label><Field l="Amount" type="number" v={item.amount??0} set={v=>set("amount",v)}/><label>Date<input type="date" value={item.adjustment_date||new Date().toISOString().slice(0,10)} onChange={e=>set("adjustment_date",e.target.value)}/></label><Field l="Reason" v={item.reason} set={v=>set("reason",v)}/><label>Status<select value={item.status||"approved"} onChange={e=>set("status",e.target.value)}><option value="approved">Approved</option><option value="pending">Pending</option><option value="rejected">Rejected</option></select></label><label className="wide">Notes<textarea value={item.notes||""} onChange={e=>set("notes",e.target.value)}/></label></>;
 }
 if(type==="utility"){
 const units=item.building_id?db.units.filter(u=>String(u.building_id)===String(item.building_id)):[];
 const custom=item.utility_type==="custom";
 return <><label>Building<select value={item.building_id||""} onChange={e=>{set("building_id",e.target.value?Number(e.target.value):null);set("unit_id",null)}}><option value="">Choose building</option>{db.buildings.map(b=><option key={b.id} value={b.id}>{b.name}</option>)}</select></label><label>Location<select value={item.scope||"unit"} onChange={e=>{set("scope",e.target.value);if(e.target.value==="building")set("unit_id",null)}}><option value="building">Communal / whole building</option><option value="unit">Specific unit</option></select></label>{item.scope==="unit"&&<label>Unit<select value={item.unit_id||""} onChange={e=>set("unit_id",e.target.value?Number(e.target.value):null)}><option value="">Choose unit</option>{units.map(u=><option key={u.id} value={u.id}>Unit {u.unit_number||u.id}</option>)}</select></label>}<label>Utility type<select value={item.utility_type||"electricity"} onChange={e=>set("utility_type",e.target.value)}><option value="electricity">Electricity</option><option value="gas">Gas</option><option value="water">Water</option><option value="internet">Internet</option><option value="heating">Heating</option><option value="solar">Solar panels</option><option value="ev_charger">EV charger</option><option value="lift">Lift</option><option value="waste">Waste</option><option value="custom">Other / custom</option></select></label>{custom&&<Field l="Custom utility name" v={item.custom_name} set={v=>set("custom_name",v)}/>}<Field l="EAN / code" v={item.ean_code} set={v=>set("ean_code",v)}/><Field l="Meter number" v={item.meter_number} set={v=>set("meter_number",v)}/><Field l="Provider" v={item.provider} set={v=>set("provider",v)}/><label>Measurement<select value={item.reading_unit||defaultReadingUnit(item.utility_type||"electricity")} onChange={e=>set("reading_unit",e.target.value)}><option value="kWh">kWh</option><option value="m³">m³</option><option value="litres">Litres</option><option value="GB">GB</option><option value="hours">Hours</option><option value="unit">Units</option><option value="none">None</option></select></label><label className="toggle-line"><input type="checkbox" checked={Boolean(item.estimate_cost)} onChange={e=>set("estimate_cost",e.target.checked)}/> Estimate cost</label><label className="toggle-line"><input type="checkbox" checked={Boolean(item.connected_meter)} onChange={e=>set("connected_meter",e.target.checked)}/> Connected meter</label>{item.connected_meter&&<label>Connection type<select value={item.connection_type||"manual"} onChange={e=>set("connection_type",e.target.value)}><option value="manual">Manual</option><option value="fluvius_p1">Fluvius P1</option><option value="home_assistant">Home Assistant</option><option value="mqtt">MQTT</option><option value="api">API</option></select></label>}<label className="wide">Notes<textarea value={item.notes||""} onChange={e=>set("notes",e.target.value)}/></label></>;
}return null}

function TenantUnitsPicker({db,unitIds,toggle}){
 const[open,setOpen]=useState({});
 const[showOther,setShowOther]=useState(false);

 function toggleBuilding(id){
  setOpen(x=>({...x,[id]:!x[id]}));
 }

 const selectedBuildingIds=db.buildings
  .filter(b=>db.units.some(u=>u.building_id===b.id&&unitIds.includes(u.id)))
  .map(b=>b.id);

 const visibleBuildings=showOther
  ?db.buildings
  :db.buildings.filter(b=>selectedBuildingIds.includes(b.id));

 function BuildingGroup({b}){
  const units=db.units.filter(u=>u.building_id===b.id);
  const selected=units.filter(u=>unitIds.includes(u.id)).length;
  return <div className="building-group" key={b.id}>
   <button type="button" className="building-toggle" onClick={()=>toggleBuilding(b.id)}>
    <span>
     <b>{b.name||"Building"}</b>
     <small>{selected?`${selected} selected`:"No units selected"}</small>
    </span>
    <span>{open[b.id]?"−":"+"}</span>
   </button>
   {open[b.id]&&<div className="building-units">
    {units.length?units.map(u=><label key={u.id} className="unit-option">
     <input type="checkbox" checked={unitIds.includes(u.id)} onChange={()=>toggle(u.id)}/>
     <span>Unit {u.unit_number||""}{u.floor?` · ${u.floor}`:""}</span>
    </label>):<div className="no-units">No units in this building.</div>}
   </div>}
  </div>
 }

 return <div className="unit-picker">
  <div className="unit-picker-title">Units</div>

  {visibleBuildings.length
   ?visibleBuildings.map(b=><BuildingGroup key={b.id} b={b}/>)
   :<div className="no-selected-building">No building selected yet.</div>}

  {db.buildings.length>selectedBuildingIds.length&&
   <button type="button" className="show-other-buildings" onClick={()=>setShowOther(x=>!x)}>
    {showOther?"Hide other buildings":"+ Add units from another building"}
   </button>}
 </div>
}
function UnitDetailsModal({unit,db,setModal,reload,initialTab,parent}){const[tab,setTab]=useState(initialTab),building=db.buildings.find(x=>x.id===unit.building_id),tenants=tenantsForUnit(db,unit.id),utilities=db.utility_ean_codes.filter(x=>String(x.unit_id)===String(unit.id));return <div className="modal-bg"><div className="modal unit-details-modal"><div className="modal-head"><div><h3>{building?.name||"Building"} · Unit {unit.unit_number||""}</h3><small>{tenants.map(t=>t.name).join(", ")||"Vacant"}</small></div><button onClick={()=>setModal(null)}>×</button></div><div className="unit-tabs">{["general","utilities","readings"].map(x=><button key={x} className={tab===x?"active":""} onClick={()=>setTab(x)}>{cap(x)}</button>)}</div><div className="unit-tab-body">{tab==="general"&&<div className="general-summary"><div><small>Building</small><b>{building?.name||""}</b></div><div><small>Unit</small><b>{unit.unit_number||""}</b></div><div><small>Floor</small><b>{unit.floor||"—"}</b></div><div><small>Tenant</small><b>{tenants.map(t=>t.name).join(", ")||"Vacant"}</b></div></div>}{tab==="utilities"&&<><div className="utilities-section-head"><h4>Utilities</h4><button className="primary" onClick={()=>setModal({type:"utility",item:{unit_id:unit.id}})}>+ Utility</button></div><div className="utility-card-grid">{utilities.map(x=><UtilityCard key={x.id} utility={x} db={db} onClick={()=>setModal({type:"utilityAccount",item:x})}/>)}{!utilities.length&&<div className="empty wide">No utilities configured for this unit.</div>}</div></>}{tab==="readings"&&<div className="all-readings">{utilities.map(x=><div key={x.id} className="readings-block"><h4>{utilityIcon(x.utility_type)} {cap(x.utility_type)}</h4><ReadingsTable utility={x} db={db}/></div>)}{!utilities.length&&<div className="empty">No utilities configured.</div>}</div>}</div><div className="modal-foot"><span/>{parent&&<button onClick={()=>setModal(parent)}>Back</button>}<button onClick={()=>setModal(null)}>Close</button></div></div></div>}
function UtilityCard({utility,db,onClick}){const latest=latestReading(db,utility.id),prev=previousReading(db,utility.id),consumption=latest&&prev?Number(latest.reading_value)-Number(prev.reading_value):null,estimate=estimateUtilityCost(db,utility,latest,prev);return <button className="utility-card" onClick={onClick}><div className="utility-card-head"><span>{utilityIcon(utility.utility_type)}</span><div><b>{utility.utility_type==="custom"?(utility.custom_name||"Custom utility"):cap(utility.utility_type.replace("_"," "))}</b><small>{utility.provider||"No provider"}</small></div></div><div className="utility-card-body"><div><small>EAN / meter</small><span>{utility.ean_code||utility.meter_number||"—"}</span></div><div><small>Latest reading</small><span>{latest?`${latest.reading_value} ${latest.reading_unit||utility.reading_unit||""}`:"No reading"}</span></div><div><small>Consumption</small><span>{consumption==null?"—":`${consumption.toFixed(2)} ${latest?.reading_unit||utility.reading_unit||""}`}</span></div><div><small>Estimated cost</small><span>{estimate==null?"—":eur(estimate)}</span></div></div></button>}
function UtilityAccountModal({utility,db,setModal,reload,parent}){const unit=db.units.find(x=>x.id===utility.unit_id),building=db.buildings.find(x=>x.id===(utility.building_id||unit?.building_id)),readings=db.meter_readings.filter(x=>String(x.utility_id)===String(utility.id)).sort((a,b)=>String(b.reading_date||"").localeCompare(String(a.reading_date||""))),tariff=db.utility_tariffs.find(x=>String(x.utility_id)===String(utility.id)&&x.active!==false),[reading,setReading]=useState(""),[date,setDate]=useState(new Date().toISOString().slice(0,10)),[unitName,setUnitName]=useState(utility.reading_unit||defaultReadingUnit(utility.utility_type)),[rate,setRate]=useState(tariff?.unit_price??""),[fixed,setFixed]=useState(tariff?.fixed_monthly_cost??"");async function addReading(){if(reading==="")return alert("Enter a meter reading.");const{error}=await supabase.from("meter_readings").insert({utility_id:utility.id,unit_id:utility.unit_id,reading_date:date,reading_value:Number(reading),reading_unit:unitName});if(error)return alert(error.message);await reload();setModal({type:"utilityAccount",item:utility})}async function saveTariff(){if(tariff?.id){const{error}=await supabase.from("utility_tariffs").update({unit_price:Number(rate||0),fixed_monthly_cost:Number(fixed||0),active:true}).eq("id",tariff.id);if(error)return alert(error.message)}else{const{error}=await supabase.from("utility_tariffs").insert({utility_id:utility.id,unit_price:Number(rate||0),fixed_monthly_cost:Number(fixed||0),currency:"EUR",active:true});if(error)return alert(error.message)}await reload();alert("Tariff saved.")}async function deleteReading(id){if(!confirm("Delete this reading?"))return;const{error}=await supabase.from("meter_readings").delete().eq("id",id);if(error)return alert(error.message);await reload();setModal({type:"utilityAccount",item:utility})}async function deleteUtility(){if(!confirm("Delete this utility and all its readings?"))return;const{error}=await supabase.from("utility_ean_codes").delete().eq("id",utility.id);if(error)return alert(error.message);await reload();setModal({type:"unitDetails",item:unit,tab:"utilities"})}const latest=readings[0],prev=readings[1],consumption=latest&&prev?Number(latest.reading_value)-Number(prev.reading_value):null,estimate=estimateUtilityCost(db,utility,latest,prev);return <div className="modal-bg"><div className="modal utility-account-modal"><div className="modal-head"><div><h3>{utilityIcon(utility.utility_type)} {cap(utility.utility_type)}</h3><small>{building?.name||""} · {utility.scope==="building"?"Communal":`Unit ${unit?.unit_number||""}`}</small></div><button onClick={()=>setModal(null)}>×</button></div><div className="utility-summary"><div><small>Provider</small><b>{utility.provider||"—"}</b></div><div><small>Latest reading</small><b>{latest?`${latest.reading_value} ${latest.reading_unit||unitName}`:"—"}</b></div><div><small>Consumption</small><b>{consumption==null?"—":`${consumption.toFixed(2)} ${latest?.reading_unit||unitName}`}</b></div><div><small>Estimated cost</small><b>{estimate==null?"—":eur(estimate)}</b></div></div><div className="utility-account-body"><div className="readings-panel"><h4>Reading history</h4>{readings.map((r,i)=>{const next=readings[i+1],usage=next?Number(r.reading_value)-Number(next.reading_value):null;return <div className="reading-row" key={r.id}><span>{r.reading_date}</span><b>{r.reading_value} {r.reading_unit||unitName}</b><span>{usage==null?"—":`${usage.toFixed(2)} used`}</span><button className="danger subtle" onClick={()=>deleteReading(r.id)}>Delete</button></div>})}{!readings.length&&<div className="empty">No readings yet.</div>}</div><div className="utility-side"><div className="utility-form-box"><h4>Add reading</h4><Field l="Reading" type="number" v={reading} set={setReading}/><label>Date<input type="date" value={date} onChange={e=>setDate(e.target.value)}/></label><label>Unit<select value={unitName} onChange={e=>setUnitName(e.target.value)}><option value="kWh">kWh</option><option value="m³">m³</option><option value="GB">GB</option><option value="unit">unit</option></select></label><button className="primary full" onClick={addReading}>Add reading</button></div><div className="utility-form-box"><h4>Cost estimate</h4><Field l={`Price per ${unitName}`} type="number" v={rate} set={setRate}/><Field l="Fixed monthly cost" type="number" v={fixed} set={setFixed}/><button className="primary full" onClick={saveTariff}>Save tariff</button><small>Estimated cost = consumption × unit price + fixed monthly cost.</small></div></div></div><div className="modal-foot"><button className="danger" onClick={deleteUtility}>Delete utility</button><span/>{parent&&<button onClick={()=>setModal(parent)}>Back</button>}<button onClick={()=>setModal(null)}>Close</button></div></div></div>}
function ReadingsTable({utility,db}){const readings=db.meter_readings.filter(x=>String(x.utility_id)===String(utility.id)).sort((a,b)=>String(b.reading_date||"").localeCompare(String(a.reading_date||"")));return <div className="compact-readings">{readings.map((r,i)=>{const next=readings[i+1],usage=next?Number(r.reading_value)-Number(next.reading_value):null;return <div key={r.id}><span>{r.reading_date}</span><b>{r.reading_value} {r.reading_unit||utility.reading_unit||""}</b><span>{usage==null?"—":usage.toFixed(2)}</span></div>})}{!readings.length&&<div className="empty">No readings.</div>}</div>}
function latestReading(db,id){return db.meter_readings.filter(x=>String(x.utility_id)===String(id)).sort((a,b)=>String(b.reading_date||"").localeCompare(String(a.reading_date||"")))[0]||null}function previousReading(db,id){return db.meter_readings.filter(x=>String(x.utility_id)===String(id)).sort((a,b)=>String(b.reading_date||"").localeCompare(String(a.reading_date||"")))[1]||null}function estimateUtilityCost(db,utility,latest,prev){if(!latest||!prev)return null;const tariff=db.utility_tariffs.find(x=>String(x.utility_id)===String(utility.id)&&x.active!==false);if(!tariff)return null;const usage=Math.max(0,Number(latest.reading_value)-Number(prev.reading_value));return usage*Number(tariff.unit_price||0)+Number(tariff.fixed_monthly_cost||0)}function utilityIcon(type){return{electricity:"⚡",gas:"🔥",water:"💧",internet:"🌐",heating:"♨️",solar:"☀️",ev_charger:"🔋",lift:"🛗",waste:"🗑️",custom:"🔌"}[type]||"🔌"}function defaultReadingUnit(type){return type==="water"||type==="gas"?"m³":type==="internet"?"GB":"kWh"}
function Field({l,v,set,type="text"}){return <label>{l}<input type={type} value={v||""} onChange={e=>set(e.target.value)}/></label>}
function payloadFor(type,f){if(type==="owner")return{name:f.name||"",email:f.email||"",phone:f.phone||"",iban:f.iban||"",notes:f.notes||""};if(type==="building")return{owner_id:f.owner_id||null,name:f.name||"",address:f.address||""};if(type==="unit")return{building_id:f.building_id||null,unit_number:f.unit_number||"",floor:f.floor||""};if(type==="tenant")return{unit_id:null,name:f.name||"",base_rent:Number(f.base_rent||0),additional_costs:Number(f.additional_costs||0),rent:Number(f.base_rent||0)+Number(f.additional_costs||0),phone:f.phone||"",email:f.email||"",iban:f.iban||"",active:true};if(type==="payment"){const d=new Date();return{tenant_id:f.tenant_id||null,year:Number(f.year||d.getFullYear()),month:Number(f.month||d.getMonth()+1),expected_amount:Number(f.expected_amount||0),paid_amount:Number(f.paid_amount||0),status:Number(f.paid_amount||0)>0?"partial":"pending"}};if(type==="adjustment")return{tenant_id:f.tenant_id||null,payment_id:f.payment_id||null,adjustment_type:f.adjustment_type||"credit",amount:Number(f.amount||0),adjustment_date:f.adjustment_date||new Date().toISOString().slice(0,10),reason:f.reason||"",notes:f.notes||"",status:f.status||"approved"};if(type==="utility")return{building_id:f.building_id||null,unit_id:f.scope==="unit"?(f.unit_id||null):null,scope:f.scope||"unit",utility_type:f.utility_type||"electricity",custom_name:f.custom_name||"",ean_code:f.ean_code||"",meter_number:f.meter_number||"",provider:f.provider||"",reading_unit:f.reading_unit||defaultReadingUnit(f.utility_type),estimate_cost:Boolean(f.estimate_cost),connected_meter:Boolean(f.connected_meter),connection_type:f.connected_meter?(f.connection_type||"manual"):null,notes:f.notes||""};return f}
function unitsForTenant(db,id){let ids=db.tenant_units.filter(x=>String(x.tenant_id)===String(id)).map(x=>x.unit_id);return db.units.filter(u=>ids.includes(u.id)||String(u.id)===String(db.tenants.find(t=>t.id===id)?.unit_id))}
function tenantsForUnit(db,id){let ids=db.tenant_units.filter(x=>String(x.unit_id)===String(id)).map(x=>x.tenant_id);return db.tenants.filter(t=>ids.includes(t.id)||String(t.unit_id)===String(id))}
function unitLabel(db,u){let b=db.buildings.find(x=>x.id===u.building_id);return `${b?.name||"Building"} - ${u.unit_number||"Unit"}`}
function Card({l,v}){return <div className="card"><small>{l}</small><b>{v}</b></div>}function Panel({title,children}){return <div className="panel"><div className="panel-head"><h3>{title}</h3></div><div className="panel-body">{children}</div></div>}function List({title,add,children}){return <div className="panel"><div className="panel-head"><h3>{title}</h3><button className="primary" onClick={add}>+ Add</button></div>{React.Children.count(children)?children:<div className="empty">Nothing yet.</div>}</div>}function Row({t,s,onClick}){return <div className="row" onClick={onClick}><b>{t}</b><span>{s}</span></div>}function Tile({t,s,onClick}){return <div className="tile" onClick={onClick}><b>{t}</b><br/>{s}</div>}
createRoot(document.getElementById("root")).render(<App/>);
